const FIGURES = [{"file":"donut_verbreitung.png","theme":"stellenwert","type":"haupt","title":"Verbreitung historischer Einleitungen","caption":"Anteil der Dissertationen mit und ohne historische Einleitung im Gesamtkorpus der Tschirch-Schule (n=160). 63 % der Dissertationen (n=101) weisen eine historische Einleitung auf; 37 % (n=59) verzichten darauf. Eigene Darstellung mit R."},{"file":"linie_anteil_zeitverlauf.png","theme":"stellenwert","type":"haupt","title":"Durchschnittlicher historischer Seitenanteil nach Dekade","caption":"Durchschnittlicher historischer Seitenanteil (%) nach Dekade im Korpus der Tschirch-Schule (n=100). Die durchgezogene Linie zeigt den Mittelwert der Dissertationen mit historischer Einleitung, die gestrichelte Linie den Mittelwert über das Gesamtkorpus inklusive Dissertationen ohne historische Einleitung. Die 1880er Dekade umfasst lediglich eine Dissertation und ist daher statistisch nicht interpretierbar. Eigene Darstellung mit R."},{"file":"balken_stellenwert.png","theme":"stellenwert","type":"anhang","title":"Häufigkeitsverteilung des Stellenwerts der Historie","caption":"Absolute Anzahl der Dissertationen je Stellenwert-Stufe (1 = gering, 2 = mittel, 3 = zentral) im Analysekorpus (n = 100). Der Stellenwert 1 dominiert mit n = 57 deutlich. Eigene Darstellung mit R."},{"file":"boxplot_stellenwert_anteil.png","theme":"stellenwert","type":"anhang","title":"Validierung der Stellenwert-Skala anhand des historischen Seitenanteils","caption":"Boxplots zeigen Median, Interquartilsabstand und Whisker (1,5× IQR) pro Stellenwert-Stufe (n = 100); Punkte stellen Einzelwerte dar. Die ansteigenden Mediane stützen die Validität der ordinalen Skala. Eigene Darstellung mit R."},{"file":"abs_verteilung_dekade.png","theme":"stellenwert","type":"anhang","title":"Verbreitung historischer Einleitungen über die Erscheinungsdekaden","caption":"Gestapelte Balken zeigen die absolute Anzahl Dissertationen mit (violett) bzw. ohne (grau) historische Einleitung pro Jahrzehnt 1880–1930 (n = 160). Der Anteil ohne historische Einleitung steigt ab den 1910er Jahren deutlich an. Eigene Darstellung mit R."},{"file":"stellenwert_zeitkontext.png","theme":"stellenwert","type":"anhang","title":"Anteilige Verteilung des Stellenwerts nach Zeitkontext","caption":"Anteilige Verteilung des Stellenwerts der Historie über drei Entstehungsperioden (Hochimperialismus 1890–1913, Erster Weltkrieg 1914–1918, Zwischenkriegszeit 1919–1939). Stichprobengrössen sind in den Achsenbeschriftungen angegeben. Der Anteil zentraler Historisierung (Stufe 3) konzentriert sich im Hochimperialismus. Eigene Darstellung mit R."},{"file":"01_epochenpanel.png","theme":"epochen","type":"haupt","title":"Vorkommen historischer Epochen (Panel)","caption":"Vorkommen historischer Epochen in den Dissertationseinleitungen. (A) Absolute Häufigkeit der Nennungen pro Epoche über das gesamte Korpus (Mehrfachnennungen pro Dissertation möglich). (B) Verteilung der Epochennennungen über die Erscheinungsdekaden 1880–1930; dargestellt sind zeilenweise normalisierte Anteile (in % pro Epoche) mit absoluten Häufigkeiten in Klammern. Die Farbintensität codiert den prozentualen Anteil. Eigene Darstellung mit R."},{"file":"heatmap_epochen_dekade.png","theme":"epochen","type":"anhang","title":"Heatmap: Epochennennungen über die Dekaden","caption":"Verteilung der Epochennennungen über die Erscheinungsdekaden 1880–1930; zeilenweise normalisierte Anteile (in % pro Epoche) mit absoluten Häufigkeiten in Klammern. Altertum und Mittelalter verschwinden nach den 1910er Jahren nahezu vollständig. Eigene Darstellung mit R."},{"file":"epochen_ranking.png","theme":"epochen","type":"anhang","title":"Epochen-Ranking (absolute Häufigkeit)","caption":"Absolute Häufigkeit der Nennungen historischer Epochen über das gesamte Korpus. Das 19. Jahrhundert dominiert als Referenzepoche; Altertum, Mittelalter und Frühe Neuzeit bilden die Tiefenepochen. Eigene Darstellung mit R."},{"file":"alle_personen_tradition.png","theme":"personen","type":"haupt","title":"Vollständiges Personenranking der historischen Autoritäten","caption":"Vollständiges Personenranking der in den historischen Einleitungen genannten Autoritäten (≥ 3 Nennungen). Punktgrösse bzw. Wert codieren die absolute Anzahl Nennungen; die Farbgebung unterscheidet nach pharmaziehistorischen Traditionslinien (griechisch-römische Antike, byzantinische und arabisch-islamische Medizin, frühneuzeitliche Botanik und Pharmakochemie, Chemie und Pharmakognosie des 19. Jahrhunderts, Geographie/Handelswege, mythisch/frühgeschichtlich). Eigene Darstellung mit R."},{"file":"netzwerk_kopraesenz.png","theme":"personen","type":"haupt","title":"Ko-Zitationsnetzwerk der historischen Autoritäten","caption":"Knoten repräsentieren historische Personen, Kanten gemeinsame Nennung in derselben Dissertation; die Kantenstärke codiert die Anzahl Ko-Präsenzen (4–16). Die Knotenfarbe codiert die Traditionslinie. Dioskurides und Plinius bilden den dichtesten Kern des Netzwerks; die Chemiker des 19. Jahrhunderts schliessen über frühneuzeitliche Vermittlerfiguren (Neumann, Valentini) an den antiken Kern an. Eigene Darstellung mit R."},{"file":"kanonstabilitaet_top25.png","theme":"personen","type":"anhang","title":"Kanonstabilität der Top-25-Autoritäten","caption":"Stabilität der meistzitierten Autoritäten über den Zeitverlauf. Dioskurides und Plinius werden vom Beginn bis zum Ende der Tschirch-Ära konstant zitiert. Eigene Darstellung mit R."},{"file":"heatmap_autoritaeten_stoffklassen.png","theme":"personen","type":"anhang","title":"Heatmap: Autoritäten nach Stoffklassen","caption":"Verteilung der genannten Autoritäten über die Stoffklassen. Die antiken Autoritäten fungierten als thematisch gebundene Referenzpunkte, nicht als universale Legitimationsinstanzen. Berzelius tritt konzentriert bei Harzen auf, Neumann bei Anthrachinon-Drogen und Gummiharzen, Marco Polo ausschliesslich bei Anthrachinon-Drogen. Eigene Darstellung mit R."},{"file":"03_stoffklassenpanel.png","theme":"stoffklassen","type":"haupt","title":"Historische Tiefe nach Stoffklasse (Panel)","caption":"Historische Tiefe der Dissertationseinleitungen nach Stoffklasse. (A) Verteilung des prozentualen Anteils historischer Textpassagen am Gesamtumfang der Dissertation pro Stoffklasse. Boxplots zeigen Median, Interquartilsabstand und Whisker (1,5 × IQR); Punkte stellen Einzelwerte dar. Stichprobengrössen je Stoffklasse sind in den Achsenbeschriftungen angegeben. (B) Anteilige Verteilung des Stellenwerts der Historie (Skala 1–3) innerhalb jeder Stoffklasse. Eigene Darstellung mit R."},{"file":"boxplot_stoffklasse.png","theme":"stoffklassen","type":"anhang","title":"Historischer Seitenanteil nach Stoffklasse","caption":"Verteilung des prozentualen Anteils historischer Textpassagen am Gesamtumfang der Dissertation pro Stoffklasse. Boxplots zeigen Median, Interquartilsabstand und Whisker (1,5× IQR). Anthrachinon-Drogen und Gummiharze weisen die höchsten historischen Anteile auf. Eigene Darstellung mit R."},{"file":"stellenwert_stoffklasse.png","theme":"stoffklassen","type":"anhang","title":"Stellenwert der Historie nach Stoffklasse","caption":"Anteilige Verteilung des Stellenwerts der Historie (Skala 1–3) innerhalb jeder Stoffklasse. Die am stärksten historisierten Stoffklassen sind jene, denen Tschirch selbst seine Arbeit widmete. Eigene Darstellung mit R."},{"file":"fokus.png","theme":"stoffklassen","type":"anhang","title":"Thematischer Fokus der historischen Einleitungen","caption":"Thematischer Fokus der historischen Einleitungen im Gesamtkorpus (n = 100). Absolute Nennungen pro Themenfeld; Mehrfachnennungen pro Dissertation sind möglich. Die Drogen- bzw. Materia-medica-Geschichte dominiert, gefolgt von Naturwissenschafts- und Disziplingeschichte. Eigene Darstellung mit R."},{"file":"boxplot_herkunft.png","theme":"herkunft","type":"anhang","title":"Historischer Seitenanteil nach Herkunftsland","caption":"Boxplots zeigen Median, Interquartilsabstand und Whisker (1,5× IQR); Punkte stellen Einzelwerte dar. Stichprobengrössen je Herkunftsland sind in den Achsenbeschriftungen angegeben. Aufgrund stark variierender Gruppengrössen ist der Befund mit Vorbehalt zu interpretieren. Eigene Darstellung mit R."},{"file":"stellenwert_herkunft.png","theme":"herkunft","type":"anhang","title":"Stellenwert nach Herkunftsland","caption":"Anteilige Verteilung des Stellenwerts der Historie (1 = gering bis 3 = zentral) innerhalb jedes Herkunftslandes. Stichprobengrössen sind in den Achsenbeschriftungen angegeben. Eigene Darstellung mit R."},{"file":"anteil_einleitung_herkunft_proportional.png","theme":"herkunft","type":"anhang","title":"Anteil Dissertationen mit historischer Einleitung nach Herkunftsland","caption":"Anteil der Dissertationen mit historischer Einleitung (%) nach Herkunftsland. Die gestrichelte Linie markiert den Korpusdurchschnitt (63 %). Absolute Werte in der Form n_mit Einl. / n_gesamt angegeben. Eigene Darstellung mit R."},{"file":"04_tschirchpanel.png","theme":"quellen","type":"haupt","title":"Tschirch-Zitationen nach Dekade (Panel)","caption":"Tschirch-Zitationen in den Dissertationseinleitungen nach Dekade. (A) Prozentualer Anteil der Dissertationen, die Tschirch in der historischen Einleitung zitieren, pro Erscheinungsdekade; Punktgrösse codiert die absolute Anzahl der Dissertationen je Dekade. (B) Absolute Nennungen einzelner Tschirch-Werke in den Einleitungen pro Dekade; Punktgrösse codiert die Anzahl der Nennungen. Eigene Darstellung mit R."},{"file":"quellentypen.png","theme":"quellen","type":"haupt","title":"Quellentypen in den Dissertationseinleitungen","caption":"Absolute Nennungen der verwendeten Quellentypen über das gesamte Korpus, farblich unterschieden nach übergeordneter Kategorie (historisch vs. naturwissenschaftlich-fachlich). Mehrfachnennungen pro Dissertation sind möglich. Fachzeitschriften, Jahresberichte und wissenschaftliche Berichte sind die meistgenutzten Quellentypen. Eigene Darstellung mit R."},{"file":"fokus_zeitkontext.png","theme":"quellen","type":"haupt","title":"Thematischer Fokus nach Zeitperiode","caption":"Anteilige Verteilung der thematischen Fokusse historischer Einleitungen über drei Entstehungsperioden (Hochimperialismus 1890–1913, Erster Weltkrieg 1914–1918, Zwischenkriegszeit 1919–1939). In der Zwischenkriegszeit findet eine leichte Verschiebung hin zur Disziplingeschichte statt. Eigene Darstellung mit R."},{"file":"quellen_verhaeltnis_stellenwert.png","theme":"quellen","type":"anhang","title":"Quellentypen nach Stellenwert der Historie","caption":"Anteile historischer (gelb) und naturwissenschaftlich-fachlicher (grün) Quellen pro Stellenwert-Stufe. Mit zunehmendem Stellenwert steigt der Anteil historischer Quellen, was die Validität der Skala stützt. Eigene Darstellung mit R."},{"file":"zeitverlauf_zitationen.png","theme":"quellen","type":"anhang","title":"Tschirch-Zitationsrate im Zeitverlauf","caption":"Prozentualer Anteil der Dissertationen, die Tschirch in der historischen Einleitung zitieren, pro Erscheinungsdekade. Die Zitationsrate bleibt über die Dekaden konstant hoch. Eigene Darstellung mit R."},{"file":"tschirch_werke.png","theme":"quellen","type":"anhang","title":"Zitierte Werke Tschirchs nach Häufigkeit","caption":"Zitierte Werke Alexander Tschirchs in den historischen Einleitungen nach Häufigkeit. Absolute Nennungen über das gesamte Analysekorpus (n = 100); Mehrfachnennungen pro Dissertation sind möglich. Eigene Darstellung mit R."},{"file":"werke_zeitverlauf_vernetzt.png","theme":"quellen","type":"anhang","title":"Tschirch-Werke im Zeitverlauf","caption":"Absolute Nennungen einzelner Tschirch-Werke in den Einleitungen pro Dekade. Die Harze und die Harzbehälter wird in ihrer Entstehungsdekade am stärksten zitiert, das Handbuch der Pharmakognosie löst es ab seinem späten Erscheinen ab. Eigene Darstellung mit R."},{"file":"ko_zitation_heatmap.png","theme":"quellen","type":"anhang","title":"Ko-Zitationsmatrix der Werke Tschirchs","caption":"Zellen geben die Anzahl Dissertationen an, in denen das jeweilige Werkpaar gemeinsam zitiert wird; die Farbintensität codiert die Häufigkeit. \"Die Harze und die Harzbehälter\" und das \"Handbuch der Pharmakognosie I\" werden auffällig selten gemeinsam zitiert. Eigene Darstellung mit R."},{"file":"02_sprachenpanel.png","theme":"narrativ","type":"haupt","title":"Narrative Form, Sprachregister und Funktion (Panel)","caption":"Narrative Form, Sprachregister und Funktion der historischen Einleitungen. (A) Absolute Häufigkeit der narrativen Formen; (B) absolute Häufigkeit des Sprachregisters; (C) absolute Häufigkeit der zugewiesenen Funktion der historischen Einleitung. Mehrfachkodierungen pro Dissertation sind möglich. Eigene Darstellung mit R."},{"file":"narrative_formen.png","theme":"narrativ","type":"anhang","title":"Narrative Formen der historischen Einleitungen","caption":"Absolute Häufigkeit der narrativen Formen (thematisch-systematisch, chronologisch, personenzentriert, teleologisch). Geschichte wurde in der Tschirch-Schule überwiegend thematisch-systematisch erzählt. Eigene Darstellung mit R."},{"file":"funktionen.png","theme":"narrativ","type":"anhang","title":"Funktionen der historischen Einleitungen","caption":"Absolute Häufigkeit der zugewiesenen Funktion (legitimierend, kanonbildend, abgrenzend, ornamental). Nach der allgemeinen Kontextualisierung dominiert die legitimierende Funktion mit Abstand. Eigene Darstellung mit R."},{"file":"sprachregister.png","theme":"narrativ","type":"anhang","title":"Sprachregister der historischen Einleitungen","caption":"Absolute Häufigkeit des Sprachregisters (wertend-positiv, deskriptiv-neutral, wertend-kritisch, autoritativ-kanonisch). Das autoritativ-kanonische Register zitiert Autoritäten ohne Einordnung oder Distanz. Eigene Darstellung mit R."},{"file":"cluster_01_dendrogramm.png","theme":"cluster-uebersicht","type":"cluster","title":"Dendrogramm der Clusteranalyse","caption":"Hierarchische Clusteranalyse auf Basis von Ward-Linkage und Gower-Distanz. Die gestrichelte Linie markiert die Schnitthöhe (Fusionsdistanz 0,5), die zu einer Vier-Cluster-Lösung führt. Das Clusterkorpus umfasst 78 Dissertationen nach Ausschluss der Stoffklassen-Kategorie \"Sonstige\". Eigene Darstellung mit R."},{"file":"cluster_07_uebersicht_kennzahlen.png","theme":"cluster-uebersicht","type":"cluster","title":"Merkmalsprofile der vier Clustertypen (Übersicht)","caption":"Oben links: Stellenwert der Historie (Skala 1–3) pro Cluster als Stripchart. Oben Mitte: prozentualer Anteil historischer Textpassagen am Gesamtumfang pro Cluster (Boxplots mit Mittelwert als Raute). Oben rechts: durchschnittliche Anzahl erwähnter Epochen pro Cluster, aufgeschlüsselt nach 19.-Jahrhundert- und Vor-19.-Jahrhundert-Epochen. Unten: Anteil der Dissertationen je Cluster, die die Epochen Altertum, Mittelalter und Frühe Neuzeit thematisieren. Eigene Darstellung mit R."},{"file":"cluster_15_kruskal_wallis_uebersicht.png","theme":"cluster-uebersicht","type":"cluster","title":"Übersicht der Kruskal-Wallis-Tests","caption":"H-Statistik je Variable; die gestrichelte rote Linie markiert die kritische Schwelle bei p = 0,05. Hochsignifikante Differenzierung (*** p < 0,001): Stellenwert (H = 77), historische Personen (H = 47,31), Vor-19.-Jh.-Epochen (H = 46,45), historische Quellentypen (H = 46,37), Gesamtepochen (H = 34,59), Anteil historisch (H = 28,31). Nicht signifikant: Seitenumfang gesamt (H = 5,04) und Erscheinungsjahr (H = 1,95). Eigene Darstellung mit R."},{"file":"cluster_02_boxplots_epochen.png","theme":"cluster-inhalt","type":"cluster","title":"Epochentiefe pro Cluster (Boxplots)","caption":"Verteilung der Anzahl erwähnter Epochen pro Cluster, aufgeschlüsselt nach Vor-19.-Jh.- und 19.-Jh.-Epochen. Typ C und Typ D dominieren bei der Epochentiefe. Eigene Darstellung mit R."},{"file":"cluster_03_epochen_heatmap.png","theme":"cluster-inhalt","type":"cluster","title":"Epochen-Heatmap pro Cluster","caption":"Anteil der Dissertationen je Cluster, die die jeweiligen Epochen thematisieren. Typ A konzentriert sich auf die Frühe Neuzeit, Typ D bildet eine vollständige Transmissionskette über alle Epochen. Eigene Darstellung mit R."},{"file":"cluster_04_top_personen.png","theme":"cluster-inhalt","type":"cluster","title":"Top-5-Personen pro Cluster","caption":"Meistzitierte historische Personen in den Einleitungen pro Cluster (A–D). Dargestellt sind die jeweils fünf häufigsten Nennungen historischer Personen, farblich unterschieden nach wissenschaftlicher Tradition. Typ A: 19. Jahrhundert dominiert; Typ B: schmaler Kanon; Typ C: multiperspektivisch (Antike + Neuzeit); Typ D: Dioskurides und Plinius mit eindeutigem Abstand. Eigene Darstellung mit R."},{"file":"cluster_05_quellentypen.png","theme":"cluster-inhalt","type":"cluster","title":"Top-5-Quellentypen pro Cluster","caption":"Meistgenutzte Quellentypen in den Einleitungen pro Cluster (A–D). Typ A und B: Dominanz naturwissenschaftlicher Quellen (kompilatorische Praxis). Typ C: Kombination naturwissenschaftlicher mit historischen Quellen. Typ D: originäre historische Quellenarbeit. Eigene Darstellung mit R."},{"file":"cluster_06_scatter_quellen_personen.png","theme":"cluster-inhalt","type":"cluster","title":"Scatter: Quellen und Personen pro Cluster","caption":"Verhältnis zwischen Anzahl genannter historischer Personen und genutzter Quellen pro Dissertation, gefärbt nach Clusterzugehörigkeit. Veranschaulicht die abgrenzbaren Cluster im Merkmalsraum. Eigene Darstellung mit R."},{"file":"cluster_08_sprachregister_cluster.png","theme":"cluster-narrativ","type":"cluster","title":"Sprachregister pro Cluster","caption":"Anteilige Verteilung der Sprachregister innerhalb der vier Dissertationstypen. Die globale Verteilung unterscheidet sich hochsignifikant zwischen den Clustern (Kruskal-Wallis, H = 47,31, p < 0,001). Eigene Darstellung mit R."},{"file":"cluster_09_narrative_form_cluster.png","theme":"cluster-narrativ","type":"cluster","title":"Narrative Formen pro Cluster","caption":"Anteilige Verteilung der narrativen Formen (thematisch-systematisch, chronologisch, personenzentriert, teleologisch) innerhalb der vier Dissertationstypen. Der Clustereffekt ist hochsignifikant (Kruskal-Wallis). Das personenzentrierte Narrativ konzentriert sich in Typ D (standardisiertes Residuum +3,8). Eigene Darstellung mit R."},{"file":"cluster_10_tschirch_zitation_cluster.png","theme":"cluster-narrativ","type":"cluster","title":"Tschirch-Zitationsrate pro Cluster","caption":"Anteil der Dissertationen, die Tschirch in der historischen Einleitung zitieren, pro Cluster (Typ A: n = 39; Typ B: n = 10; Typ C: n = 16; Typ D: n = 13). Über alle vier Typen hinweg liegt die Zitationsrate zwischen 67 % und 81 %; signifikante Unterschiede zwischen den Clustern sind nicht nachweisbar (Kruskal-Wallis, n. s.). Eigene Darstellung mit R."},{"file":"cluster_16_wozu_cluster_balken.png","theme":"cluster-narrativ","type":"cluster","title":"Funktionen der historischen Einleitung pro Cluster","caption":"Anteilige Verteilung der Funktionen (legitimierend, kanonbildend, abgrenzend, ornamental) innerhalb der vier Cluster. Die Funktion differenziert die Cluster signifikant. Die kanonbildende Funktion konzentriert sich in Typ D, die abgrenzende in Typ B, während Typ A fast ausschliesslich legitimierende Funktion zeigt. Eigene Darstellung mit R."},{"file":"cluster_17_standardisierte_residuen.png","theme":"cluster-narrativ","type":"cluster","title":"Standardisierte Residuen der narrativen Dimensionen","caption":"Standardisierte Residuen aus den Chi-Quadrat-Tests für die drei narrativen Dimensionen (narrative Form, Sprachregister, Funktion) über die vier Cluster. Werte ≥ +1,96 (rot) markieren signifikante Überrepräsentation, Werte ≤ −1,96 (blau) signifikante Unterrepräsentation. Auffällig ist die Spiegelstruktur zwischen Typ A und Typ D: personenzentriertes Narrativ (+3,8), autoritativ-kanonisches Register (+4,5) und kanonbildende Funktion (+2,4) sind in Typ D hochsignifikant überrepräsentiert, in Typ A jeweils unterrepräsentiert. Eigene Darstellung mit R."},{"file":"cluster_11_zeitkontext_cluster.png","theme":"cluster-extern","type":"cluster","title":"Zeitkontext pro Cluster","caption":"Anteilige Verteilung der Zeitkontexte (Hochimperialismus 1890–1913, Erster Weltkrieg 1914–1918, Zwischenkriegszeit 1919–1939) innerhalb der vier Dissertationstypen. Das Erscheinungsjahr zeigt keinen signifikanten Clustereffekt (Kruskal-Wallis, H = 1,95, n. s.): Alle vier Typen treten über die gesamte Tschirch-Ära auf. Eigene Darstellung mit R."},{"file":"cluster_12_dekaden_cluster.png","theme":"cluster-extern","type":"cluster","title":"Cluster-Verteilung über die Dekaden","caption":"Anteilige Verteilung der vier Dissertationstypen über die Erscheinungsdekaden 1880–1930. Absolute Häufigkeiten sind in den Balkensegmenten angegeben. Während alle vier Typen über die gesamte Schaffensperiode hinweg vorkommen, verschieben sich die relativen Häufigkeiten: Typ D konzentriert sich in den 1900er Jahren, Typ A dominiert die 1920er und 1930er. Eigene Darstellung mit R."},{"file":"cluster_13_seitenumfang_cluster.png","theme":"cluster-extern","type":"cluster","title":"Gesamtseitenumfang pro Cluster","caption":"Boxplots zeigen Median, Interquartilsabstand und Whisker (1,5× IQR); Rauten markieren den Mittelwert. Der Gesamtumfang unterscheidet die Typen nicht signifikant (Kruskal-Wallis, H = 5,04, n. s.). Die historiographische Schreibweise hängt nicht von der Länge der Arbeit ab. Eigene Darstellung mit R."},{"file":"cluster_14_herkunftsland_cluster.png","theme":"cluster-extern","type":"cluster","title":"Cluster nach Herkunftsland","caption":"Anteilige Verteilung der vier Dissertationstypen innerhalb jedes Herkunftslandes; absolute Häufigkeiten sind in den Balkensegmenten angegeben. Die Herkunft unterscheidet die Cluster nicht signifikant (Kruskal-Wallis, n. s.); Tschirchs direkter Betreuungseinfluss überlagert nationale Unterschiede. Eigene Darstellung mit R."},{"file":"cluster_18_stoffklasse_cluster.png","theme":"cluster-extern","type":"cluster","title":"Cluster nach Stoffklasse","caption":"Anteilige Verteilung der vier Dissertationstypen (A–D) innerhalb jeder Stoffklasse; absolute Häufigkeiten sind in den Balkensegmenten angegeben. Stoffklassen mit weniger als drei Dissertationen sind nicht dargestellt. Der Chi-Quadrat-Test (p < 0,001) und der Fisher-Test (p < 0,001) validieren eine hohe Signifikanz für die Clusterbildung. Gummiharze und Anthrachinon-Drogen konzentrieren sich in Typ C und Typ D; Alkaloide und Glykoside erwartungsgemäss in Typ A. Eigene Darstellung mit R."},{"file":"cluster_19_untersuchungsgegenstand_cluster.png","theme":"cluster-extern","type":"cluster","title":"Cluster nach Untersuchungsgegenstand","caption":"Anteilige Verteilung der vier Dissertationstypen nach Untersuchungsgegenstand (Rhabarber, Stocklack, Perubalsam, Guttapercha, Faulbaum, Copal); Untersuchungsgegenstände mit weniger als drei Dissertationen sind nicht dargestellt. Im Unterschied zur Stoffklasse zeigt der konkrete Untersuchungsgegenstand keine signifikante typologische Differenzierung (Kruskal-Wallis, n. s.). Eigene Darstellung mit R."}];

